pub unsafe extern "C" fn sv_save_auto_recharge(args_ptr: *mut u8, args_len: usize) -> u64 {
    let args_json = read_string(args_ptr, args_len);
    pack(with_client(|client| {
        pollster::block_on(run_envelope(async move {
            let params: SaveAutoRechargeParams = parse_args_json(&args_json)?;
            client.save_auto_recharge(params).await
        }))
    }))
}

/// `DELETE /v1/sdk/auto-recharge`
